describe("drain sink", () => {
  it("should call done with null when synchronous stream ends normally", (done) => {
    // Create a synchronous source that emits values then ends
    const values = [1, 2, 3];
    let index = 0;

    function source(end: any, cb: Function) {
      if (end) return cb(end);
      if (index >= values.length) {
        cb(true, null); // stream ended
      } else {
        cb(null, values[index++]);
      }
    }

    const collected: number[] = [];
